"use strict";(globalThis.webpackChunkapps_docs=globalThis.webpackChunkapps_docs||[]).push([[192],{3040(e){e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"coreSdkSidebar":[{"type":"link","href":"/ermis-chat-monorepo/docs/core-sdk/intro","label":"Getting Started with Core SDK","docId":"core-sdk/intro","unlisted":false},{"type":"link","href":"/ermis-chat-monorepo/docs/core-sdk/auth","label":"Authentication","docId":"core-sdk/auth","unlisted":false},{"type":"link","href":"/ermis-chat-monorepo/docs/core-sdk/client","label":"The Client (ErmisChat)","docId":"core-sdk/client","unlisted":false},{"type":"link","href":"/ermis-chat-monorepo/docs/core-sdk/users","label":"User Management","docId":"core-sdk/users","unlisted":false},{"type":"link","href":"/ermis-chat-monorepo/docs/core-sdk/channel","label":"Channels","docId":"core-sdk/channel","unlisted":false},{"type":"link","href":"/ermis-chat-monorepo/docs/core-sdk/channel-management","label":"Channel Management","docId":"core-sdk/channel-management","unlisted":false},{"type":"link","href":"/ermis-chat-monorepo/docs/core-sdk/messages","label":"Message Management","docId":"core-sdk/messages","unlisted":false},{"type":"link","href":"/ermis-chat-monorepo/docs/core-sdk/events","label":"Events & WebSockets","docId":"core-sdk/events","unlisted":false},{"type":"link","href":"/ermis-chat-monorepo/docs/core-sdk/calls","label":"Audio & Video Calls","docId":"core-sdk/calls","unlisted":false},{"type":"link","href":"/ermis-chat-monorepo/docs/core-sdk/meeting-channels","label":"Meeting Channels","docId":"core-sdk/meeting-channels","unlisted":false}],"reactSdkSidebar":[{"type":"link","href":"/ermis-chat-monorepo/docs/react/intro","label":"Getting Started with React UI Kit","docId":"react/intro","unlisted":false},{"type":"link","href":"/ermis-chat-monorepo/docs/react/components","label":"Core Components","docId":"react/components","unlisted":false},{"type":"link","href":"/ermis-chat-monorepo/docs/react/calls","label":"Calls","docId":"react/calls","unlisted":false},{"type":"link","href":"/ermis-chat-monorepo/docs/react/theming","label":"Theming & Customization","docId":"react/theming","unlisted":false},{"type":"link","href":"/ermis-chat-monorepo/docs/react/hooks","label":"Hooks","docId":"react/hooks","unlisted":false},{"type":"link","href":"/ermis-chat-monorepo/docs/react/ui-components","label":"UI Components","docId":"react/ui-components","unlisted":false},{"type":"link","href":"/ermis-chat-monorepo/docs/react/custom-messages","label":"Custom Message Renderers","docId":"react/custom-messages","unlisted":false},{"type":"link","href":"/ermis-chat-monorepo/docs/react/interactivity","label":"Message Interactivity","docId":"react/interactivity","unlisted":false},{"type":"link","href":"/ermis-chat-monorepo/docs/react/attachments","label":"Attachments & Media Uploads","docId":"react/attachments","unlisted":false},{"type":"link","href":"/ermis-chat-monorepo/docs/react/utilities","label":"Utility Functions","docId":"react/utilities","unlisted":false}]},"docs":{"core-sdk/auth":{"id":"core-sdk/auth","title":"Authentication","description":"If your application uses the default Ermis backend for user management or requires initial authentication flows independent of an existing application server, you can use the ErmisAuthProvider.","sidebar":"coreSdkSidebar"},"core-sdk/calls":{"id":"core-sdk/calls","title":"Audio & Video Calls","description":"The SDK supports 1-on-1 audio and video calls through the ErmisCallNode class. It uses a proprietary WebRTC WASM client for peer-to-peer media streaming, with the Ermis Relay infrastructure for NAT traversal and signaling.","sidebar":"coreSdkSidebar"},"core-sdk/channel":{"id":"core-sdk/channel","title":"Channels","description":"The Channel class encapsulates all real-time communication functionality for a specific chat channel. It handles messages, reactions, thread replies, typing indicators, and manages a localized state for rapid user interface updates.","sidebar":"coreSdkSidebar"},"core-sdk/channel-management":{"id":"core-sdk/channel-management","title":"Channel Management","description":"Once a channel is created and initialized, you can manage its members, permissions, notifications, and lifecycle. The available operations differ depending on the channel type.","sidebar":"coreSdkSidebar"},"core-sdk/client":{"id":"core-sdk/client","title":"The Client (ErmisChat)","description":"The ErmisChat class is the main entry point to the Core SDK. It manages instances, authentication, global web-socket connections, and HTTP REST logic.","sidebar":"coreSdkSidebar"},"core-sdk/events":{"id":"core-sdk/events","title":"Events & WebSockets","description":"The Ermis Chat SDK handles real-time data using persistent WebSockets (isomorphic-ws). When client.connectUser() is called, a persistent connection is established. The StableWSConnection class will automatically monitor connection health and attempt to reconnect upon failure.","sidebar":"coreSdkSidebar"},"core-sdk/intro":{"id":"core-sdk/intro","title":"Getting Started with Core SDK","description":"Ermis Chat SDK is the JavaScript/TypeScript client for the Ermis Chat platform. It allows you to connect to the Ermis Chat backend, manage channels, send messages, and handle real-time WebSockets and WebRTC events.","sidebar":"coreSdkSidebar"},"core-sdk/meeting-channels":{"id":"core-sdk/meeting-channels","title":"Meeting Channels","description":"Meeting channels are specialized streams designed to accommodate audio-video conferencing spaces with simple and constrained setups.","sidebar":"coreSdkSidebar"},"core-sdk/messages":{"id":"core-sdk/messages","title":"Message Management","description":"All message operations are executed through the specific Channel instance that the messages belong to.","sidebar":"coreSdkSidebar"},"core-sdk/users":{"id":"core-sdk/users","title":"User Management","description":"Once a user is connected to ErmisChat, broad query methods for discovering other actors in the system, viewing contacts, and updating own profiles are available directly within the global client session.","sidebar":"coreSdkSidebar"},"react/attachments":{"id":"react/attachments","title":"Attachments & Media Uploads","description":"Media transfer capabilities are natively embedded into the `` module, backed by an efficient caching architecture inside the Ermis SDK.","sidebar":"reactSdkSidebar"},"react/calls":{"id":"react/calls","title":"Audio & Video Calls","description":"Ermis Chat React provides a complete, built-in Direct Call system for 1-on-1 audio and video calls. It integrates seamlessly with the chat UI through the ChatProvider, ErmisCallProvider, and ErmisCallUI components.","sidebar":"reactSdkSidebar"},"react/components":{"id":"react/components","title":"Core Components","description":"Ermis Chat React provides a set of highly customizable Core Components. The props below are directly mapped from the SDK\'s types.ts file to give you exhaustive control over overrides and behavior.","sidebar":"reactSdkSidebar"},"react/custom-messages":{"id":"react/custom-messages","title":"Custom Message Renderers","description":"Ermis Chat provides native rendering support for various dynamic message layouts via the MessageRenderers mapping system. While the default UI handles text, attachments, and polls seamlessly, most production applications require heavily customized designs for system alerts, interactive poll cards, or custom signals.","sidebar":"reactSdkSidebar"},"react/hooks":{"id":"react/hooks","title":"Hooks","description":"Ermis Chat React provides 19 powerful React hooks that allow you to build completely custom UI interfaces. These hooks directly tap into the core SDK state and real-time events.","sidebar":"reactSdkSidebar"},"react/interactivity":{"id":"react/interactivity","title":"Message Interactivity","description":"Ermis Chat React comes pre-packaged with a complete suite of messaging features including reactions, message actions (Edit, Copy, Delete), replies/quotes, and forwarding.","sidebar":"reactSdkSidebar"},"react/intro":{"id":"react/intro","title":"Getting Started with React UI Kit","description":"The @ermis-network/ermis-chat-react package provides ready-to-use, highly customizable React components for building chat applications. It depends tightly on the core SDK for state management and API communication.","sidebar":"reactSdkSidebar"},"react/theming":{"id":"react/theming","title":"Theming & Customization","description":"Providing a bespoke aesthetic is incredibly straightforward with the React UI Kit. It is built natively with CSS variables (CSS Custom Properties) tracking a BEM-inspired methodology.","sidebar":"reactSdkSidebar"},"react/ui-components":{"id":"react/ui-components","title":"UI Components","description":"Beyond the base providers, the UI Kit exposes several standalone UI Components. These functional elements are utilized internally but exported explicitly so you can reuse them when building custom views.","sidebar":"reactSdkSidebar"},"react/utilities":{"id":"react/utilities","title":"Utility Functions","description":"Beyond layouts and hooks, the Ermis Chat React framework exports a suite of specialized functional utilities. These helpers natively power the core platform and are exposed so you can easily maintain parsing synchronicity across your custom components.","sidebar":"reactSdkSidebar"}}}}')}}]);